where.if:
EXISTS (
    SELECT 1
    FROM order_item seller_oi
    WHERE seller_oi.orderNo = o.orderNo
      AND seller_oi.sellerUid = #{sellerUid}
)

mapper.select:
SELECT o.orderNo, o.memberUid, CASE WHEN #{sellerUid} IS NULL OR #{sellerUid} = '' THEN o.orderPrice ELSE COALESCE(( SELECT SUM(oi.originalPrice * oi.count) FROM order_item oi WHERE oi.orderNo = o.orderNo AND oi.sellerUid = #{sellerUid} ), 0) END AS orderPrice, CASE WHEN #{sellerUid} IS NULL OR #{sellerUid} = '' THEN o.orderDiscount ELSE COALESCE(( SELECT SUM(GREATEST((oi.originalPrice * oi.count) - oi.total, 0)) FROM order_item oi WHERE oi.orderNo = o.orderNo AND oi.sellerUid = #{sellerUid} ), 0) END AS orderDiscount, o.couponIssueId, CASE WHEN #{sellerUid} IS NULL OR #{sellerUid} = '' THEN COALESCE(( SELECT SUM(oi.shippingFee) FROM order_item oi WHERE oi.orderNo = o.orderNo ), 0) ELSE COALESCE(( SELECT SUM(oi.shippingFee) FROM order_item oi WHERE oi.orderNo = o.orderNo AND oi.sellerUid = #{sellerUid} ), 0) END AS shippingFee, o.usedPoints, CASE WHEN #{sellerUid} IS NULL OR #{sellerUid} = '' THEN o.orderTotal ELSE COALESCE(( SELECT SUM(oi.total + oi.shippingFee) FROM order_item oi WHERE oi.orderNo = o.orderNo AND oi.sellerUid = #{sellerUid} ), 0) END AS orderTotal, o.receiver, o.phone, o.zipCode, o.addr1, o.addr2, o.payMethod, o.status, o.orderNote, o.createdAt, m.name AS memberName, (SELECT SUM(oi.count) FROM `order_item` oi WHERE oi.orderNo = o.orderNo
AND oi.sellerUid = #{sellerUid}
) AS totalCount FROM `order` o LEFT JOIN `member` m ON o.memberUid = m.uid
ORDER BY o.orderNo DESC LIMIT #{limit} OFFSET #{offset}
